INSERT INTO "public"."iot_bridge" ("id", "config_json", "name", "enable", "status", "type", "direction", "route", "del_flag", "create_by", "create_time", "update_by", "update_time", "remark", "tenant_id", "tenant_name") VALUES (2, '{"name": "萤石云平台获取直播URL", "method": "POST", "hostUrl": "https://open.ys7.com/api/lapp/v2/live/address/get", "hostUrlbody": "open.ys7.com/api/lapp/v2/live/address/get", "requestQuerys": "{\"accessToken\":\"必填：授权access_token\",\"deviceSerial\":\"必填：设备序列号例如427734222\",\"channelNo\":\"可选：通道号\",\"protocol\":\"可选：流播放协议，1-ezopen、2-hls、3-rtmp、4-flv，默认为1\",\"code\":\"可选：ezopen协议地址的设备的视频加密密码\",\"expireTime\":\"可选：过期时长，单位秒；针对hls/rtmp/flv设置有效期，相对时间；30秒-720天\",\"type\":\"可选：地址的类型，1-预览，2-本地录像回放，3-云存储录像回放\",\"quality\":\"可选：视频清晰度，1-高清（主码流）、2-流畅（子码流）\",\"startTime\":\"可选：本地录像/云存储录像回放开始时间\",\"stopTime\":\"可选：本地录像/云存储录像回放结束时间\",\"gbchannel\":\"可选：国标设备的通道编号，视频通道编号ID\"}", "requestHeaders": null}', '萤石云平台获取直播URL', '1', 1, 3, 2, '', '0', 'admin', NULL, '', NULL, NULL, 1, '蜂信物联');
INSERT INTO "public"."iot_bridge" ("id", "config_json", "name", "enable", "status", "type", "direction", "route", "del_flag", "create_by", "create_time", "update_by", "update_time", "remark", "tenant_id", "tenant_name") VALUES (3, '{"name": "海康综合安防平台分页获取监控点资源", "method": "POST", "hostUrl": "https://127.0.0.1：443/artemis/api/resource/v1/cameras", "hostUrlbody": "127.0.0.1：443/artemis/api/resource/v1/cameras", "requestConfig": "{\"appKey\":\"appKey\",\"appSecret\":\"appSecret\"}", "requestQuerys": "{\"pageNo\":\"pageNo\",\"pageSize\":\"pageSize\"}", "requestHeaders": null}', '海康综合安防平台分页获取监控点资源', '1', 0, 3, 2, '', '0', 'admin', NULL, '', NULL, NULL, 1, '蜂信物联');
INSERT INTO "public"."iot_bridge" ("id", "config_json", "name", "enable", "status", "type", "direction", "route", "del_flag", "create_by", "create_time", "update_by", "update_time", "remark", "tenant_id", "tenant_name") VALUES (4, '{"name": "海康综合安防平台获取监控点预览取流URLv2", "method": "POST", "hostUrl": "https://127.0.0.1:443/artemis/api/video/v2/cameras/previewURLs", "hostUrlbody": "127.0.0.1:443/artemis/api/video/v2/cameras/previewURLs", "requestConfig": "{\"appKey\":\"appKey\",\"appSecret\":\"appSecret\"}", "requestQuerys": "{\"cameraIndexCode\":\"必填：监控点唯一标识，分页获取监控点资源接口获取返回参数cameraIndexCode\",\"streamType\":\"可选：码流类型，0:主码流 1:子码流 2:第三码流 参数不填，默认为主码流\",\"protocol\":\"可选：取流协议，\\\"hik\\\",\\\"rtsp\\\",\\\"rtmp\\\",\\\"hls\\\",\\\"ws\\\"\",\"transmode\":\"可选：传输协议，0:UDP 1:TCP 默认是TCP\",\"streamform\":\"可选：输出码流转封装格式，“ps”:PS封装格式、“rtp”:RTP封装协议\"}", "requestHeaders": null}', '海康综合安防平台获取监控点预览取流URLv2', '1', 0, 3, 2, '', '0', 'admin', NULL, '', NULL, NULL, 1, '蜂信物联');
INSERT INTO "public"."iot_bridge" ("id", "config_json", "name", "enable", "status", "type", "direction", "route", "del_flag", "create_by", "create_time", "update_by", "update_time", "remark", "tenant_id", "tenant_name") VALUES (5, '{"name": "海康综合安防平台获取监控点回放取流URLv2", "method": "POST", "hostUrl": "https://127.0.0.1:443/artemis/api/video/v2/cameras/playbackURLs", "hostUrlbody": "127.0.0.1:443/artemis/api/video/v2/cameras/playbackURLs", "requestConfig": "{\"appKey\":\"appKey\",\"appSecret\":\"appSecret\"}", "requestQuerys": "{\"cameraIndexCode\":\"必填：监控点唯一标识，分页获取监控点资源接口获取返回参数cameraIndexCode\",\"recordLocation\":\"可选：存储类型,0：中心存储 1：设备存储 默认为中心存储\",\"protocol\":\"可选：取流协议，“hik”，“rtsp”，“ws”，“hls”，“rtmp”，\",\"transmode\":\"可选：0:UDP 1:TCP\",\"beginTime\":\"必填：开始时间\",\"endTime\":\"必填：结束时间\",\"streamform\":\"可选：输出码流转封装格式，“ps”:PS封装格式、“rtp”:RTP封装协议。\",\"lockType\":\"可选：录像锁定类型，0-查询全部录像；1-查询未锁定录像；2-查询已锁定录像，不传默认值为0。\"}", "requestHeaders": null}', '海康综合安防平台获取监控点回放取流URLv2', '1', 0, 3, 2, '', '0', 'admin', NULL, '', NULL, NULL, 1, '蜂信物联');
